*/

/**
 * 사이트맵 조회
 */
scwin.retrieveSiteMap = function(resBody) {
	var menuList = [ [], [], [] ]; // 각 treeView에 세팅될 json Array 3개

	var useMenuObjList = []; // useYn이 Y인 메뉴 집합
	var topMenuIndexList = []; // 최상위 메뉴의 index 집합
	var dtlmenuList= $p.top().wfm_left.getWindow().dltLeftMenuList;
	if (dtlmenuList != undefined) {
		dltTreeData.setJSON(dtlmenuList.getAllJSON());

		var allMenuList = dltTreeData.getAllJSON();
		if (allMenuList != undefined && allMenuList != null && allMenuList.length > 0) {
			// useYn 이 Y인 메뉴만 추려서 목록을 만든다
			for (var i = 0 ; i < allMenuList.length ; i++) {
				if (allMenuList[i].useYn == "Y") {
					useMenuObjList.push(allMenuList[i]);
				}
			}
			// 최상위 메뉴의 index를 목록화한다.
			for (var i = 0 ; i < useMenuObjList.length ; i++) {
				if (useMenuObjList[i].menuLvl == 1) {
					topMenuIndexList.push(i);
				}
			}

			// 1/3 지점, 2/3 지점의 인덱스를 구한다.
			var _2ndIndex = scwin.getNearNumberIndex(topMenuIndexList , (allMenuList.length / 3 * 1));
			_2ndIndex = dltTreeData.getMatchedIndex("menuId" , useMenuObjList[_2ndIndex].menuId);
			var _3rdIndex = scwin.getNearNumberIndex(topMenuIndexList , (allMenuList.length / 3 * 2));
			_3rdIndex = dltTreeData.getMatchedIndex("menuId" , useMenuObjList[_3rdIndex].menuId);

			// 최상위항목을 3등분하여 각 treeView에 분배한다.
			var curtTreeIndex = 0;
			for (var i = 0 ; i < allMenuList.length ; i++) {
				if (i >= _3rdIndex && menuList[1].length > 0 && allMenuList[i].menuLvl == 1) {
					curtTreeIndex = 2;
				} else if (i >= _2ndIndex && menuList[0].length > 0 && allMenuList[i].menuLvl == 1) {
					curtTreeIndex = 1;
				}
				menuList[curtTreeIndex].push(allMenuList[i]);
			}

			// useYn 이 "Y" 인 항목만 표시
			dltTreeData.setColumnFilter({ type : "row" , colIndex : "useYn" , key : "Y" , condition : "and" , exactMatch : true });
			dltTreeData1.setJSON(menuList[0]);
			dltTreeData1.setColumnFilter({ type : "row" , colIndex : "useYn" , key : "Y" , condition : "and" , exactMatch : true });
			dltTreeData2.setJSON(menuList[1]);
			dltTreeData2.setColumnFilter({ type : "row" , colIndex : "useYn" , key : "Y" , condition : "and" , exactMatch : true });
			dltTreeData3.setJSON(menuList[2]);
			dltTreeData3.setColumnFilter({ type : "row" , colIndex : "useYn" , key : "Y" , condition : "and" , exactMatch : true });
		}
	}
};

/**
 * 주어진 배얼에서 p와 가장 근사한 배열값의 인덱스를 리턴
 */
scwin.getNearNumberIndex = function(array, p) {
	var tmp = 0;
	var min = 999999;
	var found = 0;

	for (var i = 0 ; i < array.length ; i++) {
		tmp = array[i] - p;
		if (Math.abs(min) > Math.abs(tmp)) {
			min = tmp;
			found = array[i];
		}
	}
	return found;
};

/**
 * 페이지 로딩 후 자동수행
 * (기존 navigator_.xml 을 사용하지 않았으므로 initScreen() 자동실행이 되지 않음)
 */
scwin.siteMapBody_onpageload = function() {
	scwin.initScreen ();
};

/**
 * 사이트맵 아이템 클릭시 left 메뉴의 item을 클릭한 것과 동일한 효과를 내도록 한다.
 */
scwin.trvSiteMap_onlabelclick = function(value,nodeElement,index) {
	// 최하위 노드만 동작
	var childNodes = this.getChildData(value);
	if (childNodes.length == 0) {
		scwin.siteMapOpen(value);
	}
};

/**
 * left 메뉴 open 이벤트
 * left 메뉴가 있어야 정상동작한다
 */
scwin.siteMapOpen = function(value) {
	if ($p.top().wfm_left.getWindow().trvMenu != undefined && $p.top().wfm_left.getWindow().scwin.trvMenu_onclick != undefined) {
		// 부모노드가 있으면 부모노드부터 클릭 이벤트 발생
		var parentValue = $p.top().wfm_left.getWindow().trvMenu.getParentValue(value);
		if (parentValue != undefined && parentValue != null && parentValue != "") {
			scwin.siteMapOpen(parentValue);
		}
		// 부모노드를 오픈 후에는 자기 자신을 오픈
		var menuNode = $p.top().wfm_left.getWindow().trvMenu.findNodeByValue(value, true);
		//$p.top().wfm_left.getWindow().scwin.trvMenu_onclick(value);
		top.$("#"+$p.top().wfm_left.id+"_trvMenu_label_" + menuNode.index).trigger("click");
		//$p.top().wfm_left.getWindow().$p.$("#trvMenu_label_" + menuNode.index).trigger("click");
	}
};
